afterSnapshot.source:
// Decide which simple risks apply to a single route leg, given already-resolved
// forecast numbers for that leg's destination/arrival hour.
// Pure function: no network or closure dependencies, so it is directly unit-testable.
//
// bearing:      the leg's course over ground (degrees, direction of travel).
// hourData:     forecast at the arrival hour { windSpeed, windDirection, precipitation, cloudCover, pressure }.
// prevHourData: forecast at the hour before arrival (for pressure-trend), or null.
// arriveUtcMs:  the leg's estimated arrival time, UTC ms.
// sunsetUtcMs / sunriseUtcMs: that destination/day's sun times, UTC ms, or null when unknown.
// thresholds:   tunable cutoffs from config { headwindAngleDeg, headwindMinKnots,
//               lowVisPrecipMm, lowVisCloudPct, pressureLowHpa, pressureDropHpa }.
//
// Returns { warnings: [{ code, label }], riskLevel } where riskLevel is
// 'ok' (0 warnings), 'caution' (1), or 'warning' (2+).
function computeLegWarnings(
  bearing: number,
  hourData: any,
  prevHourData: any,
  arriveUtcMs: number,
  sunsetUtcMs: number | null,
  sunriseUtcMs: number | null,
  thresholds: any
) {
  const warnings: any[] = [];

  // Defensive defaults for thresholds so a missing config never throws
  const t = thresholds || {};
  const headwindAngleDeg = typeof t.headwindAngleDeg === 'number' ? t.headwindAngleDeg : 60;
  const headwindMinKnots = typeof t.headwindMinKnots === 'number' ? t.headwindMinKnots : 10;
  const lowVisPrecipMm = typeof t.lowVisPrecipMm === 'number' ? t.lowVisPrecipMm : 2;
  const lowVisCloudPct = typeof t.lowVisCloudPct === 'number' ? t.lowVisCloudPct : 95;
  const pressureLowHpa = typeof t.pressureLowHpa === 'number' ? t.pressureLowHpa : 1005;
  const pressureDropHpa = typeof t.pressureDropHpa === 'number' ? t.pressureDropHpa : 3;

  // Smallest absolute angle between two compass bearings (0..180)
  const angularDiff = (a: number, b: number) => {
    const d = Math.abs((((a - b) % 360) + 360) % 360);
    return d > 180 ? 360 - d : d;
  };

  const h = hourData || {};

  // --- Headwind: wind blowing FROM roughly where we're heading TO ---
  // windDirection is the meteorological "from" direction. If that aligns with
  // the leg bearing (the way we travel) within the tolerance, and it's strong
  // enough, the boat is sailing into the wind.
  if (typeof h.windDirection === 'number' && typeof h.windSpeed === 'number') {
    const offAxis = angularDiff(h.windDirection, bearing);
    if (offAxis <= headwindAngleDeg && h.windSpeed >= headwindMinKnots) {
      warnings.push({ code: 'headwind', label: 'Headwind' });
    }
  }

  // --- Low visibility: heavy precip OR near-total overcast (fog proxy) ---
  const precip = typeof h.precipitation === 'number' ? h.precipitation : 0;
  const cloud = typeof h.cloudCover === 'number' ? h.cloudCover : 0;
  if (precip >= lowVisPrecipMm || cloud >= lowVisCloudPct) {
    warnings.push({ code: 'low_visibility', label: 'Low visibility' });
  }

  // --- Pressure drop nearby: low absolute pressure OR a sharp hour-over-hour fall ---
  if (typeof h.pressure === 'number') {
    const lowAbsolute = h.pressure <= pressureLowHpa;
    let sharpFall = false;
    if (prevHourData && typeof prevHourData.pressure === 'number') {
      // A fall means current is lower than the previous hour by the threshold
      sharpFall = (prevHourData.pressure - h.pressure) >= pressureDropHpa;
    }
    if (lowAbsolute || sharpFall) {
      warnings.push({ code: 'pressure_drop', label: 'Pressure drop nearby' });
    }
  }

  // --- Arrival after sunset: arrive in darkness (after sunset or before sunrise) ---
  if (typeof arriveUtcMs === 'number' && isFinite(arriveUtcMs)) {
    const afterSunset = typeof sunsetUtcMs === 'number' && arriveUtcMs >= sunsetUtcMs;
    const beforeSunrise = typeof sunriseUtcMs === 'number' && arriveUtcMs <= sunriseUtcMs;
    if (afterSunset || beforeSunrise) {
      warnings.push({ code: 'after_sunset', label: 'Arrival after sunset' });
    }
  }

  // Risk tier scales with the number of concurrent warnings
  let riskLevel = 'ok';
  if (warnings.length === 1) riskLevel = 'caution';
  else if (warnings.length >= 2) riskLevel = 'warning';

  return { warnings, riskLevel };
}
